package main
import("crypto/sha256";"encoding/hex";"encoding/json";"flag";"fmt";"math";"os")
type B struct{Mass float64 `json:"mass"`;P [3]float64 `json:"position"`;V [3]float64 `json:"velocity"`};type In struct{Steps int `json:"steps"`;Dt float64 `json:"deltaTime"`;Bodies []B `json:"bodies"`}
func main(){ip:=flag.String("input","","");op:=flag.String("output","","");flag.Parse();x,_:=os.ReadFile(*ip);var in In;json.Unmarshal(x,&in);b:=in.Bodies;for s:=0;s<in.Steps;s++{for i:=0;i<len(b);i++{for j:=i+1;j<len(b);j++{var d [3]float64;var r float64;for k:=0;k<3;k++{d[k]=b[j].P[k]-b[i].P[k];r+=d[k]*d[k]};m:=in.Dt/(r*math.Sqrt(r));for k:=0;k<3;k++{b[i].V[k]+=d[k]*b[j].Mass*m;b[j].V[k]-=d[k]*b[i].Mass*m}}};for i:=range b{for k:=0;k<3;k++{b[i].P[k]+=in.Dt*b[i].V[k]}}};var e float64;ph,vh:=sha256.New(),sha256.New();for i:=range b{var v float64;for k:=0;k<3;k++{v+=b[i].V[k]*b[i].V[k];fmt.Fprintf(ph,"%.9f,",b[i].P[k]);fmt.Fprintf(vh,"%.9f,",b[i].V[k])};e+=.5*b[i].Mass*v;for j:=i+1;j<len(b);j++{var r float64;for k:=0;k<3;k++{d:=b[i].P[k]-b[j].P[k];r+=d*d};e-=b[i].Mass*b[j].Mass/math.Sqrt(r)}};o:=struct{Benchmark string `json:"benchmark"`;Version int `json:"version"`;Count int `json:"bodyCount"`;Energy float64 `json:"finalEnergy"`;P string `json:"positionChecksum"`;V string `json:"velocityChecksum"`}{"nbody",1,len(b),e,hex.EncodeToString(ph.Sum(nil)),hex.EncodeToString(vh.Sum(nil))};x,_=json.Marshal(o);os.WriteFile(*op,x,0644)}
